import * as React from "react";
import { act, render, screen } from "@testing-library/react";

import { clickButton, expectCurrentImageToBe, expectToContainButton, lightbox } from "../utils.js";
import { Fullscreen, Thumbnails, Video } from "../../../src/plugins/index.js";
import { LightboxExternalProps } from "../../../src/index.js";

function renderLightbox(props?: LightboxExternalProps) {
    return render(
        lightbox({
            slides: [{ src: "image1" }, { src: "image2" }, { src: "image3" }],
            plugins: [Thumbnails],
            ...props,
        })
    );
}

function queryThumbnails() {
    return screen
        .queryAllByRole("button")
        .filter((el) => el.className.split(" ").includes("yarl__thumbnails_thumbnail"));
}

function clickThumbnail(image: string) {
    act(() => {
        queryThumbnails()
            .find((el) => Boolean(el.querySelector(`img[src='${image}']`)))!
            .click();
    });
}

function expectThumbnails(visible = true) {
    expect(queryThumbnails().length > 0).toBe(visible);
}

function expectNavigation() {
    clickButton("Next");
    clickButton("Previous");
    expectThumbnails();
}

describe("Thumbnails", () => {
    it("renders without crashing", () => {
        renderLightbox();
        expectNavigation();
    });

    it("supports thumbnails toggle button", () => {
        renderLightbox({ thumbnails: { showToggle: true } });
        expectThumbnails();

        clickButton("Hide thumbnails");
        expectThumbnails(false);

        clickButton("Show thumbnails");
        expectThumbnails();
    });

    it("supports thumbnails navigation", () => {
        renderLightbox({ carousel: { preload: 1 } });
        expectCurrentImageToBe("image1");

        clickThumbnail("image2");
        expectCurrentImageToBe("image2");

        clickThumbnail("image1");
        expectCurrentImageToBe("image1");
    });

    it("supports thumbnails position", () => {
        renderLightbox({ thumbnails: { position: "top" } });
        expectNavigation();

        renderLightbox({ thumbnails: { position: "bottom" } });
        expectNavigation();

        renderLightbox({ thumbnails: { position: "start" } });
        expectNavigation();

        renderLightbox({ thumbnails: { position: "end" } });
        expectNavigation();
    });

    it("works with Fullscreen", () => {
        // Fullscreen plugin must be listed first
        renderLightbox({ plugins: [Fullscreen, Thumbnails] });
        expectThumbnails();
    });

    it("supports custom thumbnails button", () => {
        renderLightbox({
            thumbnails: { showToggle: true },
            render: { buttonThumbnails: () => React.createElement("button", { type: "button" }, "Custom button") },
        });
        expectToContainButton("Custom button");
    });

    it("supports thumbnails customization", () => {
        renderLightbox({ thumbnails: { border: 2, borderRadius: 5, width: 60, height: 40, padding: 10, gap: 10 } });
        expectThumbnails();
    });

    it("supports finite carousel", () => {
        renderLightbox({ carousel: { finite: true } });
        expectThumbnails();

        clickButton("Next");
        expectThumbnails();
    });

    it("supports video thumbnails", () => {
        renderLightbox({
            slides: [{ type: "video", poster: "poster", sources: [{ src: "video", type: "video/mp4" }] }],
            plugins: [Thumbnails, Video],
        });
        clickThumbnail("poster");
    });

    it("supports unknown slide types", () => {
        // @ts-expect-error
        renderLightbox({ slides: [{ type: "custom" }] });
        expectThumbnails();
    });

    it("supports custom thumbnails", () => {
        renderLightbox({ render: { thumbnail: () => React.createElement("img", { src: "custom" }) } });
        clickThumbnail("custom");
    });
});
import * as React from "react";
import { act, screen } from "@testing-library/react";
import { vi } from "vitest";

import Lightbox from "../../src/index.js";

export function lightbox(props?: Parameters<typeof Lightbox>[0]) {
    return <Lightbox open {...props} />;
}

export function querySelector(selector: string) {
    return screen.getByRole("presentation").querySelector(selector);
}

export function findCurrentSlide() {
    return querySelector("div.yarl__slide_current");
}

export function findCurrentImage() {
    return findCurrentSlide()?.querySelector("img")?.src;
}

export function expectCurrentImageToBe(source: string) {
    expect(findCurrentImage()).toContain(source);
}

export function clickButton(name: string) {
    act(() => {
        screen.getByRole("button", { name }).click();
    });
}

export function queryButton(name: string) {
    return screen.queryByRole("button", { name });
}

export function expectToContainButton(name: string) {
    expect(queryButton(name)).toBeInTheDocument();
}

export function expectNotToContainButton(name: string) {
    expect(queryButton(name)).not.toBeInTheDocument();
}

// Workaround for @testing-library/user-event fake timers bug
// https://github.com/testing-library/react-testing-library/issues/1197
export async function withFakeTimers(callback: (props: { runAllTimers: () => void }) => void) {
    const jestCopy = globalThis.jest;

    globalThis.jest = {
        ...globalThis.jest,
        advanceTimersByTime: vi.advanceTimersByTime.bind(vi),
    };

    try {
        vi.useFakeTimers();

        await callback({
            runAllTimers: () => {
                act(() => {
                    vi.runAllTimers();
                });
            },
        });
    } finally {
        vi.useRealTimers();

        globalThis.jest = jestCopy;
    }
}

import * as React from "react";

import {
    ACTION_NEXT,
    ACTION_PREV,
    ACTION_SWIPE,
    CLASS_FLEX_CENTER,
    cleanup,
    clsx,
    cssClass,
    cssVar,
    getSlide,
    hasSlides,
    Slide,
    useAnimation,
    useEventCallback,
    useEvents,
    useLightboxProps,
    useLightboxState,
    useRTL,
} from "../../index.js";
import { cssPrefix, cssThumbnailPrefix } from "./utils.js";
import { Thumbnail } from "./Thumbnail.js";
import { defaultThumbnailsProps, useThumbnailsProps } from "./props.js";

function isHorizontal(position: ReturnType<typeof useThumbnailsProps>["position"]) {
    return ["top", "bottom"].includes(position);
}

function boxSize(thumbnails: ReturnType<typeof useThumbnailsProps>, dimension: number, includeGap?: boolean) {
    return dimension + 2 * (thumbnails.border + thumbnails.padding) + (includeGap ? thumbnails.gap : 0);
}

export type ThumbnailsTrackProps = {
    visible: boolean;
    containerRef: React.RefObject<HTMLDivElement>;
};

export function ThumbnailsTrack({ visible, containerRef }: ThumbnailsTrackProps) {
    const track = React.useRef<HTMLDivElement | null>(null);

    const { carousel, styles } = useLightboxProps();
    const { slides, globalIndex, animation } = useLightboxState();
    const { publish, subscribe } = useEvents();
    const isRTL = useRTL();

    const thumbnails = useThumbnailsProps();
    const { position, width, height, border, borderRadius, padding, gap, vignette } = thumbnails;

    const index = globalIndex;
    const animationDuration = animation?.duration || 0;
    const offset = (animationDuration > 0 && animation?.increment) || 0;

    const { prepareAnimation } = useAnimation<number>(track, (snapshot) => ({
        keyframes: isHorizontal(position)
            ? [
                  {
                      transform: `translateX(${
                          (isRTL ? -1 : 1) * boxSize(thumbnails, width, true) * offset + snapshot
                      }px)`,
                  },
                  { transform: "translateX(0)" },
              ]
            : [
                  {
                      transform: `translateY(${boxSize(thumbnails, height, true) * offset + snapshot}px)`,
                  },
                  { transform: "translateY(0)" },
              ],
        duration: animationDuration,
        easing: animation?.easing,
    }));

    const handleControllerSwipe = useEventCallback(() => {
        let animationOffset = 0;
        if (containerRef.current && track.current) {
            const containerRect = containerRef.current.getBoundingClientRect();
            const trackRect = track.current.getBoundingClientRect();
            animationOffset = isHorizontal(position)
                ? trackRect.left - containerRect.left - (containerRect.width - trackRect.width) / 2
                : trackRect.top - containerRect.top - (containerRect.height - trackRect.height) / 2;
        }

        prepareAnimation(animationOffset);
    });

